mapper.update:
UPDATE pet_vaccine_record
vaccine_name = #{vaccineName}, vaccine_date = #{vaccineDate}, next_date = #{nextDate}, hospital = #{hospital}, doctor = #{doctor}, remark = #{remark},
WHERE id = #{id}

mapper.select:
SELECT v.id, v.vaccine_name as vaccineName, DATE_FORMAT(v.vaccine_date, '%Y-%m-%d') as vaccineDate, DATE_FORMAT(v.next_date, '%Y-%m-%d') as nextDate, DATE_FORMAT(v.create_time, '%Y-%m-%d %H:%i:%s') as createTime, v.hospital, v.doctor, v.remark, p.id as petId, p.name as petName, u.id as ownerId, u.username as ownerName FROM pet_vaccine_record v LEFT JOIN pet_profile p ON v.pet_id = p.id LEFT JOIN user u ON p.user_id = u.id
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR v.vaccine_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY v.create_time DESC LIMIT #{offset}, #{limit}
